#include <stdio.h>
#include <string.h>

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        static int freq[100001];
        memset(freq, 0, sizeof(freq));
        for (int i = 0; i < N; ++i) {
            int p; scanf("%d", &p);
            ++freq[p];
        }
        int possible = 1;
        for (int s = 2; s <= N; ++s) {
            if (freq[s] && freq[s] % s != 0) { possible = 0; break; }
        }
        printf(possible ? "YES\n" : "NO\n");
    }
    return 0;
}

