#!/usr/bin/env python3
import sys

def solve():
    data = list(map(int, sys.stdin.read().strip().split()))
    if not data:
        return
    it = iter(data)
    T = next(it)
    out = []
    for _ in range(T):
        N = next(it)
        freq = {}
        for _ in range(N):
            p = next(it)
            freq[p] = freq.get(p, 0) + 1
        ok = all(cnt % size == 0 for size, cnt in freq.items())
        out.append('YES' if ok else 'NO')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

